const msg = ($json.message?.text || '').trim().toLowerCase();
let command = 'unknown';
if (msg.startsWith('/deploy') || msg === 'deploy') command = 'deploy';
else if (msg.startsWith('/status') || msg === 'status') command = 'status';
else if (msg.startsWith('/restart') || msg === 'restart') command = 'restart';
else if (msg.startsWith('/logs') || msg === 'logs') command = 'logs';
else if (msg.startsWith('/health') || msg === 'health') command = 'health';
const chatId = $json.message?.chat?.id || '7218843690';
return [{ json: { command, chat_id: chatId, original: msg } }];

const cmd = $input.first().json.command;
let sshCmd = '';
let label = '';

switch (cmd) {
  case 'deploy':
    sshCmd = 'cd ~/lumespos && git pull origin Staging && pnpm --filter ./artifacts/pos-app --filter ./artifacts/api-server run build && cp $(find node_modules -name "table.sql" -path "*connect-pg*" | head -1) artifacts/api-server/dist/ && pm2 restart pos-api && sleep 2 && curl -s http://127.0.0.1:3000/api/health';
    label = 'Deploy';
    break;
  case 'status':
    sshCmd = 'echo "=== PM2 ===" && pm2 status && echo "" && echo "=== RAM ===" && free -m && echo "" && echo "=== DISK ===" && df -h / && echo "" && echo "=== UPTIME ===" && uptime && echo "" && echo "=== HEALTH ===" && curl -s -o /dev/null -w "HTTP %{http_code}" http://127.0.0.1:3000/api/health';
    label = 'Status';
    break;
  case 'restart':
    sshCmd = 'pm2 restart pos-api && sleep 2 && pm2 status';
    label = 'Restart';
    break;
  case 'logs':
    sshCmd = 'pm2 logs pos-api --lines 30 --nostream';
    label = 'Logs';
    break;
  case 'health':
    sshCmd = 'curl -s -o /dev/null -w "%{http_code}" http://127.0.0.1:3000/api/health';
    label = 'Health';
    break;
}

const chatId = $input.first().json.chat_id || '7218843690';
return [{ json: { command: cmd, ssh_cmd: sshCmd, label: label, chat_id: chatId } }];

return [{
